class MessageValidator:
    """Validates and sanitizes incoming SQS messages to prevent injection attacks."""

    MAX_PAYLOAD_SIZE = 256 * 1024  # 256 KB (SQS max)
    MAX_STRING_LENGTH = 10000
    MAX_NESTING_DEPTH = 5
    ALLOWED_PAYLOAD_KEYS_PATTERN = re.compile(r'^[a-zA-Z0-9_\-\.]+$')

    @classmethod
    def validate_and_parse(cls, raw_body: str, message_id: str, receipt_handle: str,
                           attributes: Optional[Dict] = None) -> SQSMessage:
        """Parse, validate, and sanitize an SQS message body."""
        if not isinstance(raw_body, str):
            raise ValueError("Message body must be a string")

        if len(raw_body) > cls.MAX_PAYLOAD_SIZE:
            raise ValueError(f"Message body exceeds maximum size of {cls.MAX_PAYLOAD_SIZE} bytes")

        try:
            body = json.loads(raw_body)
        except json.JSONDecodeError as e:
            raise ValueError(f"Invalid JSON in message body: {e}")

        if not isinstance(body, dict):
            raise ValueError("Message body must be a JSON object")

        msg_type_str = body.get("message_type")
        if not isinstance(msg_type_str, str):
            raise ValueError("Missing or invalid 'message_type' field")

        # Whitelist validation: only allow known message types
        try:
            message_type = MessageType(msg_type_str)
        except ValueError:
            raise ValueError(
                f"Unknown message type: '{cls._sanitize_log_string(msg_type_str)}'. "
                f"Allowed types: {[t.value for t in MessageType]}"
            )

        payload = body.get("payload", {})
        if not isinstance(payload, dict):
            raise ValueError("'payload' must be a JSON object")

        # Deep validate and sanitize the payload
        sanitized_payload = cls._validate_payload(payload, depth=0)

        return SQSMessage(
            message_id=message_id,
            receipt_handle=receipt_handle,
            message_type=message_type,
            payload=sanitized_payload,
            raw_body=raw_body,
            attributes=attributes or {}
        )

    @classmethod
    def _validate_payload(cls, data: Any, depth: int) -> Any:
        """Recursively validate and sanitize payload data."""
        if depth > cls.MAX_NESTING_DEPTH:
            raise ValueError(f"Payload nesting exceeds maximum depth of {cls.MAX_NESTING_DEPTH}")

        if data is None or isinstance(data, bool):
            return data

        if isinstance(data, (int, float)):
            if isinstance(data, float) and (data != data or data == float('inf') or data == float('-inf')):
                raise ValueError("Payload contains invalid numeric value (NaN or Infinity)")
            return data

        if isinstance(data, str):
            if len(data) > cls.MAX_STRING_LENGTH:
                raise ValueError(f"String value exceeds maximum length of {cls.MAX_STRING_LENGTH}")
            # Remove null bytes which could be used for injection
            sanitized = data.replace('\x00', '')
            return sanitized

        if isinstance(data, list):
            if len(data) > 1000:
                raise ValueError("Array exceeds maximum length of 1000 elements")
            return [cls._validate_payload(item, depth + 1) for item in data]

        if isinstance(data, dict):
            if len(data) > 100:
                raise ValueError("Object exceeds maximum of 100 keys")
            sanitized = {}
            for key, value in data.items():
                if not isinstance(key, str):
                    raise ValueError("All payload keys must be strings")
                if not cls.ALLOWED_PAYLOAD_KEYS_PATTERN.match(key):
                    raise ValueError(
                        f"Invalid payload key: '{cls._sanitize_log_string(key)}'. "
                        f"Keys must match pattern: {cls.ALLOWED_PAYLOAD_KEYS_PATTERN.pattern}"
                    )
                sanitized[key] = cls._validate_payload(value, depth + 1)
            return sanitized

        raise ValueError(f"Unsupported data type in payload: {type(data).__name__}")

    @staticmethod
    def _sanitize_log_string(value: str, max_length: int = 100) -> str:
        """Sanitize a string for safe logging to prevent log injection."""
        sanitized = value[:max_length]
        # Remove control characters that could be used for log injection
        sanitized = re.sub(r'[\x00-\x1f\x7f-\x9f]', '', sanitized)
        if len(value) > max_length:
            sanitized += "...[truncated]"
        return sanitized


