class HandlerRegistry:
    """Registry mapping message types to their handlers. Uses explicit registration only."""

    def __init__(self):
        self._handlers: Dict[MessageType, MessageHandler] = {}

    def register(self, message_type: MessageType, handler: MessageHandler) -> None:
        if not isinstance(message_type, MessageType):
            raise TypeError("message_type must be a MessageType enum member")
        if not isinstance(handler, MessageHandler):
            raise TypeError("handler must be a MessageHandler instance")
        self._handlers[message_type] = handler
        logger.info(f"Registered handler for message type: {message_type.value}")

    def get_handler(self, message_type: MessageType) -> MessageHandler:
        handler = self._handlers.get(message_type)
        if handler is None:
            raise ValueError(
                f"No handler registered for message type: {message_type.value}. "
                f"Registered types: {[t.value for t in self._handlers.keys()]}"
            )
        return handler

    @property
    def registered_types(self) -> list:
        return [t.value for t in self._handlers.keys()]


class SQSWorker:
    """SQS message polling and processing worker."""

    def __init__(
        self,
        queue_url: str,
        region_name: str = "us-east-1",
        max_messages: int = 10,
        wait_time_seconds: int = 20,
        visibility_timeout: int = 300,
        max_retries: int = 3,
        backoff_base: float = 2.0,
        aws_access_key_id: Optional[str] = None,
        aws_secret_access_key: Optional[str] = None,
    ):
        self.queue_url = queue_url
        self.max_messages = min(max(1, max_messages), 10)  # SQS allows 1-10
        self.wait_time_seconds = min(max(0, wait_time_seconds), 20)  # SQS allows 0-20
        self.visibility_timeout = visibility_timeout
        self.max_retries = max_retries
        self.backoff_base = backoff_base
        self._running = False
        self._handler_registry = HandlerRegistry()

        session_kwargs = {"region_name": region_name}
        if aws_access_key_id and aws_secret_access_key:
            session_kwargs["aws_access_key_id"] = aws_access_key_id
            session_kwargs["aws_secret_access_key"] = aws_secret_access_key

        session = boto3.Session(**session_kwargs)
        self._sqs_client = session.client("sqs")

        # Register default handlers
        self._register_default_handlers()

    def _register_default_handlers(self):
        self._handler_registry.register(MessageType.SEND_EMAIL, SendEmailHandler())
        self._handler_registry.register(MessageType.PROCESS_IMAGE, ProcessImageHandler())
        self._handler_registry.register(MessageType.GENERATE_REPORT, GenerateReportHandler())
        self._handler_registry.register(MessageType.DATA_SYNC, DataSyncHandler())
        self._handler_registry.register(MessageType.CLEANUP, CleanupHandler())

    def register_handler(self, message_type: MessageType, handler: MessageHandler) -> None:
        self._handler_registry.register(message_type, handler)

    def _poll_messages(self) -> list:
        try:
            response = self._sqs_client.receive_message(
                QueueUrl=self.queue_url,
                MaxNumberOfMessages=self.max_messages,
                WaitTimeSeconds=self.wait_time_seconds,
                VisibilityTimeout=self.visibility_timeout,
                AttributeNames=["All"],
                MessageAttributeNames=["All"],
            )
            return response.get("Messages", [])
        except ClientError as e:
            logger.error(f"Error polling SQS: {e.response['Error']['Code']}: {e.response['Error']['Message']}")
            return []
        except Exception as e:
            logger.error(f"Unexpected error polling SQS: {type(e).__name__}")
            return []

    def _delete_message(self, receipt_handle: str) -> bool:
        try:
            self._sqs_client.delete_message(
                QueueUrl=self.queue_url,
                ReceiptHandle=receipt_handle,
            )
            return True
        except ClientError as e:
            logger.error(f"Error deleting message: {e.response['Error']['Code']}")
            return False

    def _change_message_visibility(self, receipt_handle: str, timeout: int) -> bool:
        try:
            self._sqs_client.change_message_visibility(
                QueueUrl=self.queue_url,
                ReceiptHandle=receipt_handle,
                VisibilityTimeout=timeout,
            )
            return True
        except ClientError as e:
            logger.error(f"Error changing message visibility: {e.response['Error']['Code']}")
            return False

    def _process_single_message(self, raw_message: dict) -> ProcessingResult:
        message_id = raw_message.get("MessageId", "unknown")
        receipt_handle = raw_message.get("ReceiptHandle", "")
        body = raw_message.get("Body", "")
        attributes = raw_message.get("Attributes", {})

        # Check approximate receive count for poison pill detection
        receive_count = int(attributes.get("ApproximateReceiveCount", "1"))
        if receive_count > self.max_retries:
            logger.warning(
                f"Message {message_id} has been received {receive_count} times, "
                f"exceeding max retries ({self.max_retries}). Sending to DLQ or deleting."
            )
            self._delete_message(receipt_handle)
            return ProcessingResult(
                success=False,
                message_id=message_id,
                message_type="unknown",
                error=f"Max retries exceeded (received {receive_count} times)"
            )

        # Step 1: Validate and parse the message
        try:
            validated_message = MessageValidator.validate_and_parse(
                raw_body=body,
                message_id=message_id,
                receipt_handle=receipt_handle,
                attributes=attributes,
            )
        except ValueError as e:
            logger.warning(
                f"Message validation failed for {message_id}: {e}"
            )
            # Delete invalid messages to prevent infinite reprocessing
            self._delete_message(receipt_handle)
            return ProcessingResult(
                success=False,
                message_id=message_id,
                message_type="unknown",
                error=f"Validation failed: {e}"
            )

        # Step 2: Get the appropriate handler
        try:
            handler = self._handler_registry.get_handler(validated_message.message_type)
        except ValueError as e:
            logger.error(f"No handler for message {message_id}: {e}")
            self._delete_message(receipt_handle)
            return ProcessingResult(
                success=False,
                message_id=message_id,
                message_type=validated_message.message_type.value,
                error=str(e)
            )

        # Step 3: Process the message
        try:
            result = handler.handle(validated_message)
            if result.success:
                self._delete_message(receipt_handle)
                logger.info(
                    f"Successfully processed message {message_id} "
                    f"(type: {validated_message.message_type.value})"
                )
            else:
                # Handler indicated failure but didn't raise - let message become visible again
                logger.warning(
                    f"Handler returned failure for message {message_id}: {result.error}"
                )
            return result

        except ValueError as e:
            # Payload validation error from handler - message is malformed, delete it
            logger.warning(
                f"Payload validation failed in handler for {message_id}: {e}"
            )
            self._delete_message(receipt_handle)
            return ProcessingResult(
                success=False,
                message_id=message_id,
                message_type=validated_message.message_type.value,
                error=f"Handler validation failed: {e}"
            )
        except Exception as e:
            # Unexpected error - let message become visible again for retry
            logger.error(
                f"Error processing message {message_id}: {type(e).__name__}: {e}",
                exc_info=True
            )
            # Exponential backoff for retries
            backoff_timeout = min(
                int(self.backoff_base ** receive_count),
                self.visibility_timeout
            )
            self._change_message_visibility(receipt_handle, backoff_timeout)
            return ProcessingResult(
                success=False,
                message_id=message_id,
                message_type=validated_message.message_type.value,
                error=f"Processing error: {type(e).__name__}"
            )

    def process_batch(self) -> list:
        """Poll and process a batch of messages."""
        messages = self._poll_messages()
        results = []

        if not messages:
            logger.debug("No messages received")
            return results

        logger.info(f"Received {len(messages)} messages")

        for raw_message in messages:
            result = self._process_single_message(raw_message)
            results.append(result)

        successful = sum(1 for r in results if r.success)
        failed = sum(1 for r in results if not r.success)
        logger.info(f"Batch complete: {successful} successful, {failed} failed")

        return results

    def start(self):
        """Start the worker polling loop."""
        self._running = True
        logger.info(
            f"Starting SQS worker - Queue: {self.queue_url}, "
            f"Registered handlers: {self._handler_registry.registered_types}"
        )

        # Set up graceful shutdown
        def signal_handler(signum, frame):
            logger.info(f"Received signal {signum}, shutting down gracefully...")
            self._running = False

        signal.signal(signal.SIGINT, signal_handler)
        signal.signal(signal.SIGTERM, signal_handler)

        consecutive_errors = 0
        max_consecutive_errors = 10

        while self._running:
            try:
                self.process_batch()
                consecutive_errors = 0
            except Exception as e:
                consecutive_errors += 1
                logger.error(
                    f"Unexpected error in polling loop ({consecutive_errors}/{max_consecutive_errors}): "
                    f"{type(e).__name__}: {e}",
                    exc_info=True
                )
                if consecutive_errors >= max_consecutive_errors:
                    logger.critical(
                        f"Too many consecutive errors ({consecutive_errors}), shutting down"
                    )
                    self._running = False
                    break
                # Exponential backoff on consecutive errors
                sleep_time = min(2 ** consecutive_errors, 60)
                logger.info(f"Backing off for {sleep_time} seconds")
                time.sleep(sleep_time)

        logger.info("SQS worker stopped")

    def stop(self):
        """Signal the worker to stop."""
        logger.info("Stop requested")
        self._running = False


def create_worker(
    queue_url: str,
    region_name: str = "us-east-1",
    **kwargs
) -> SQSWorker:
    """Factory function to create a configured SQS worker."""
    worker = SQSWorker(
        queue_url=queue_url,
        region_name=region_name,
        **kwargs
    )
    return worker


